// Анализ свечей 1m
const candles1m = $input.first().json;

function parseCandles(data) {
  return data.map(c => ({
    time: c[0],
    open: parseFloat(c[1]),
    high: parseFloat(c[2]),
    low: parseFloat(c[3]),
    close: parseFloat(c[4]),
    volume: parseFloat(c[5])
  }));
}

function analyzeCandles(candles) {
  if (!candles || candles.length === 0) return { direction: 'NEUTRAL', score: 0, patterns: [] };

  const lastCandle = candles[candles.length - 1];
  const prevCandle = candles[candles.length - 2] || lastCandle;

  let bullishScore = 0;
  let bearishScore = 0;
  const patterns = [];

  // Объём
  const avgVol = candles.slice(-20).reduce((s, c) => s + c.volume, 0) / 20;
  const volumeConfirm = lastCandle.volume > avgVol * 1.5;
  if (volumeConfirm) {
    if (lastCandle.close > lastCandle.open) bullishScore += 2;
    else bearishScore += 2;
  }

  // Тело свечи
  const body = Math.abs(lastCandle.close - lastCandle.open);
  const range = lastCandle.high - lastCandle.low;
  const bodyRatio = range > 0 ? body / range : 0;

  if (bodyRatio > 0.7) {
    if (lastCandle.close > lastCandle.open) {
      bullishScore += 3;
      patterns.push('bull_marubozu');
    } else {
      bearishScore += 3;
      patterns.push('bear_marubozu');
    }
  } else if (bodyRatio < 0.3) {
    patterns.push('doji');
  }

  // Тени
  const upperShadow = lastCandle.high - Math.max(lastCandle.open, lastCandle.close);
  const lowerShadow = Math.min(lastCandle.open, lastCandle.close) - lastCandle.low;

  if (lowerShadow > body * 2 && lowerShadow > upperShadow) {
    bullishScore += 2;
    patterns.push('hammer');
  }
  if (upperShadow > body * 2 && upperShadow > lowerShadow) {
    bearishScore += 2;
    patterns.push('shooting_star');
  }

  // RSI (приблизительный)
  let rsi = 50;
  const gains = [];
  const losses = [];
  for (let i = Math.max(1, candles.length - 14); i < candles.length; i++) {
    const change = candles[i].close - candles[i-1].close;
    if (change > 0) gains.push(change);
    else losses.push(Math.abs(change));
  }
  if (gains.length > 0 && losses.length > 0) {
    const avgGain = gains.reduce((a,b) => a+b, 0) / 14;
    const avgLoss = losses.reduce((a,b) => 0, 0) / 14;
    rsi = 100 - (100 / (1 + avgGain / (avgLoss || 1)));
  }

  if (rsi < 30) bullishScore += 2;
  else if (rsi > 70) bearishScore += 2;

  // Тренд по EMA
  const ema9 = candles.slice(-9).reduce((s, c) => s + c.close, 0) / 9;
  const ema21 = candles.slice(-21).reduce((s, c) => s + c.close, 0) / 21;

  if (ema9 > ema21) {
    bullishScore += 2;
  } else {
    bearishScore += 2;
  }

  const totalScore = bullishScore + bearishScore;
  let direction = 'NEUTRAL';
  if (bullishScore > bearishScore * 1.3 && totalScore > 4) direction = 'LONG';
  else if (bearishScore > bullishScore * 1.3 && totalScore > 4) direction = 'SHORT';

  return {
    direction,
    score: Math.max(bullishScore, bearishScore),
    patterns,
    rsi: Math.round(rsi),
    volumeConfirm,
    lastPrice: lastCandle.close,
    emaTrend: ema9 > ema21 ? 'bullish' : 'bearish'
  };
}

const candles = parseCandles(candles1m);
const analysis = analyzeCandles(candles);

return [{ json: { ...analysis, timeframe: '1m' } }];

