// Анализ стакана (Order Book)
const orderBook = $input.first().json;

function analyzeOrderBook(ob) {
  if (!ob || !ob.bids || !ob.asks || ob.bids.length === 0) {
    return { direction: 'NEUTRAL', score: 0, spreadPct: 999, domScore: 0, imbalance: 0 };
  }

  const bestBid = parseFloat(ob.bids[0][0]);
  const bestAsk = parseFloat(ob.asks[0][0]);
  const midPrice = (bestBid + bestAsk) / 2;
  const spread = bestAsk - bestBid;
  const spreadPct = (spread / midPrice) * 100;

  let bullishScore = 0;
  let bearishScore = 0;

  // DOM Score
  const bid1 = parseFloat(ob.bids[0][1]);
  const ask1 = parseFloat(ob.asks[0][1]);
  const domScore = bid1 + ask1 > 0 ? (bid1 - ask1) / (bid1 + ask1) : 0;

  if (domScore > 0.3) bullishScore += 3;
  else if (domScore > 0.1) bullishScore += 1;
  if (domScore < -0.3) bearishScore += 3;
  else if (domScore < -0.1) bearishScore += 1;

  // Imbalance
  let totalBid = 0;
  let totalAsk = 0;

  for (let i = 0; i < Math.min(20, ob.bids.length); i++) {
    totalBid += parseFloat(ob.bids[i][1]);
  }
  for (let i = 0; i < Math.min(20, ob.asks.length); i++) {
    totalAsk += parseFloat(ob.asks[i][1]);
  }

  const imbalance = totalBid + totalAsk > 0 ? (totalBid - totalAsk) / (totalBid + totalAsk) : 0;

  if (imbalance > 0.3) bullishScore += 2;
  else if (imbalance > 0.15) bullishScore += 1;
  if (imbalance < -0.3) bearishScore += 2;
  else if (imbalance < -0.15) bearishScore += 1;

  // Walls
  const avgBidVol = totalBid / Math.min(20, ob.bids.length);
  const avgAskVol = totalAsk / Math.min(20, ob.asks.length);
  const bidWalls = ob.bids.filter(b => parseFloat(b[1]) > avgBidVol * 3).length;
  const askWalls = ob.asks.filter(a => parseFloat(a[1]) > avgAskVol * 3).length;

  if (bidWalls > askWalls && bidWalls > 0) bullishScore += 2;
  if (askWalls > bidWalls && askWalls > 0) bearishScore += 2;

  // Spread
  if (spreadPct < 0.05 && domScore > 0.1) bullishScore += 1;
  if (spreadPct < 0.05 && domScore < -0.1) bearishScore += 1;

  const totalScore = bullishScore + bearishScore;
  let direction = 'NEUTRAL';
  if (bullishScore > bearishScore * 1.3 && totalScore > 3) direction = 'LONG';
  else if (bearishScore > bullishScore * 1.3 && totalScore > 3) direction = 'SHORT';

  return {
    direction,
    score: Math.max(bullishScore, bearishScore),
    spreadPct: parseFloat(spreadPct.toFixed(4)),
    domScore: parseFloat(domScore.toFixed(3)),
    imbalance: parseFloat(imbalance.toFixed(3)),
    bidWalls,
    askWalls
  };
}

const analysis = analyzeOrderBook(orderBook);

return [{ json: analysis }];

// Группировка всех анализов
const analysis1m = $input.item.json['{{ $json.analysis1m }}'] || {};
const analysis5m = $input.item.json['{{ $json.analysis5m }}'] || {};
const analysis1h = $input.item.json['{{ $json.analysis1h }}'] || {};
const orderBook = $input.item.json['{{ $json.orderBook }}'] || {};
const ticker = $input.item.json['{{ $json.ticker }}'] || {};

// Получаем данные из предыдущих нод
const items = $input.all();

let analysis1mData = {};
let analysis5mData = {};
let analysis1hData = {};
let orderBookData = {};
let tickerData = {};

for (const item of items) {
  if (item.json.timeframe === '1m') analysis1mData = item.json;
  if (item.json.timeframe === '5m') analysis5mData = item.json;
  if (item.json.timeframe === '1h') analysis1hData = item.json;
  if (item.json.spreadPct !== undefined && item.json.domScore !== undefined) orderBookData = item.json;
  if (item.json.lastPrice !== undefined && !item.json.timeframe) tickerData = item.json;
}

// Группировка
const group = {
  timestamp: new Date().toISOString(),
  symbol: '{{ $json.symbol }}',
  analysis: {
    '1m': analysis1mData,
    '5m': analysis5mData,
    '1h': analysis1hData
  },
  orderBook: orderBookData,
  ticker: tickerData
};

// Итоговый анализ
let longCount = 0;
let shortCount = 0;
const directions = [analysis1mData.direction, analysis5mData.direction, analysis1hData.direction, orderBookData.direction];

for (const dir of directions) {
  if (dir === 'LONG') longCount++;
  if (dir === 'SHORT') shortCount++;
}

let finalDirection = 'NEUTRAL';
let confidence = 0;

if (longCount >= 2 && longCount > shortCount) {
  finalDirection = 'LONG';
  confidence = Math.min(0.9, 0.5 + longCount * 0.15);
} else if (shortCount >= 2 && shortCount > longCount) {
  finalDirection = 'SHORT';
  confidence = Math.min(0.9, 0.5 + shortCount * 0.15);
}

// Проверка спреда
if (orderBookData.spreadPct > 0.1) {
  confidence *= 0.7;
}

group.final = {
  direction: finalDirection,
  confidence: Math.round(confidence * 100) / 100,
  longCount,
  shortCount,
  recommendation: finalDirection === 'NEUTRAL' 
    ? 'Подождать лучших условий' 
    : `Рекомендуется ${finalDirection === 'LONG' ? 'покупка' : 'продажа'}`
};

return [{ json: group }];

// Анализ новостей
const news = $input.first().json;

let sentiment = 'neutral';
let score = 0;

if (news.articles && news.articles.length > 0) {
  const keywords = {
    bullish: ['surge', 'bull', 'rise', 'gain', 'growth', 'positive', 'breakout', 'rally'],
    bearish: ['crash', 'bear', 'fall', 'drop', 'negative', 'dump', 'decline', 'sell']
  };

  let bullishCount = 0;
  let bearishCount = 0;

  for (const article of news.articles) {
    const title = (article.title || '').toLowerCase();
    const desc = (article.description || '').toLowerCase();
    const text = title + ' ' + desc;

    for (const word of keywords.bullish) {
      if (text.includes(word)) bullishCount++;
    }
    for (const word of keywords.bearish) {
      if (text.includes(word)) bearishCount++;
    }
  }

  if (bullishCount > bearishCount) {
    sentiment = 'bullish';
    score = Math.min(3, bullishCount - bearishCount);
  } else if (bearishCount > bullishCount) {
    sentiment = 'bearish';
    score = Math.min(3, bearishCount - bullishCount);
  }
}

return [{ json: {
  sentiment,
  score,
  articles: news.articles || []
} }];

