// Финальная группировка с AI
const analysis = $input.item.json;
const aiResponse = $input.all().find(i => i.json.content);

let aiRecommendation = 'WAIT';
if (aiResponse && aiResponse.json.content) {
  const content = JSON.stringify(aiResponse.json.content).toUpperCase();
  if (content.includes('OPEN_LONG')) aiRecommendation = 'LONG';
  else if (content.includes('OPEN_SHORT')) aiRecommendation = 'SHORT';
  else aiRecommendation = 'WAIT';
}

// Объединяем все данные
const final = {
  ...analysis,
  aiRecommendation,
  aiResponse: aiResponse ? aiResponse.json.content : null,
  timestamp: new Date().toISOString()
};

// Риск-менеджмент
const userRisk = {{ $json.userRiskPercent || 2 }}; // Процент риска от депозита
const minConfidence = {{ $json.minConfidence || 0.65 }};

let shouldTrade = false;
let reason = '';

if (analysis.final.confidence >= minConfidence && aiRecommendation !== 'WAIT') {
  shouldTrade = true;
  reason = 'Сигнал соответствует критериям риск-менеджмента';
} else if (analysis.final.confidence < minConfidence) {
  reason = `Низкая уверенность: ${Math.round(analysis.final.confidence * 100)}% < ${minConfidence * 100}%`;
} else {
  reason = 'AI рекомендует подождать';
}

final.riskManagement = {
  shouldTrade,
  reason,
  confidence: analysis.final.confidence,
  aiRecommendation,
  recommendedAction: shouldTrade 
    ? `Открыть позицию ${analysis.final.direction}` 
    : 'Подождать лучших условий'
};

return [{ json: final }];
